<?php include "app/views/layouts/header.php"; ?><div class="d-flex justify-content-between align-items-start mb-3"><p class="text-muted mb-0">Pending transactions and approval tasks.</p><a class="btn btn-outline-primary h-25" href="index.php?page=notifications&mark_all=1">Mark All Read</a></div><div class="card p-3"><?php foreach($notifications as $n): ?><div class="border-bottom py-3 <?= $n['is_read']?'':'bg-light' ?>"><h6 class="fw-bold"><?= htmlspecialchars($n['title']) ?> <?= !$n['is_read']?'<span class="badge bg-danger">New</span>':'' ?></h6><p><?= htmlspecialchars($n['message']) ?></p><small><?= htmlspecialchars($n['created_at']) ?></small><div class="mt-2"><?php if($n['link']): ?><a class="btn btn-sm btn-outline-primary" href="<?= htmlspecialchars($n['link']) ?>">Open</a><?php endif; ?> <a class="btn btn-sm btn-outline-secondary" href="index.php?page=notifications&read=<?= $n['id'] ?>">Read</a> <a class="btn btn-sm btn-outline-danger" href="index.php?page=notifications&delete=<?= $n['id'] ?>">Delete</a></div></div><?php endforeach; ?><?php if(empty($notifications)): ?><p class="text-muted mb-0">No notifications yet.</p><?php endif; ?></div><?php include "app/views/layouts/footer.php"; ?>
